package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    void testGetAutoFlush_DefaultInstance() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.getAutoFlush());
    }

    @Test
    void testGetAutoFlush_CustomFalse() {
        CSVFormat format = createCSVFormatWithAutoFlush(false);
        assertFalse(format.getAutoFlush());
    }

    @Test
    void testGetAutoFlush_CustomTrue() {
        CSVFormat format = createCSVFormatWithAutoFlush(true);
        assertTrue(format.getAutoFlush());
    }

    private CSVFormat createCSVFormatWithAutoFlush(boolean autoFlush) {
        try {
            Method withAutoFlushMethod = CSVFormat.class.getMethod("withAutoFlush", boolean.class);
            return (CSVFormat) withAutoFlushMethod.invoke(CSVFormat.DEFAULT, autoFlush);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}
